import (
    "crypto/rand"
    "encoding/base32"
    "strings"
)

func NewCouponCode() (string, error) {
    var buf [8]byte
    if _, err := rand.Read(buf[:]); err != nil {
        return "", err
    }
    enc := base32.StdEncoding.WithPadding(base32.NoPadding).EncodeToString(buf[:])
    enc = strings.ToUpper(strings.TrimRight(enc, "="))
    return enc[:12], nil
}

