var couponLimiters sync.Map

func couponLimiterFor(ip string) *rate.Limiter {
    l, _ := couponLimiters.LoadOrStore(ip, rate.NewLimiter(rate.Every(12*time.Second), 5))
    return l.(*rate.Limiter)
}

func CouponRateLimit(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        if !couponLimiterFor(r.RemoteAddr).Allow() {
            http.Error(w, "Too many attempts", http.StatusTooManyRequests)
            return
        }
        next.ServeHTTP(w, r)
    })
}
